public Task Publish<TNotification>(TNotification notification, CancellationToken cancellationToken = default)
        where TNotification : INotification
    {
        if (notification == null)
        {
            throw new ArgumentNullException(nameof(notification));
        }

        return PublishNotification(notification, cancellationToken);
    }

    public Task Publish(object notification, CancellationToken cancellationToken = default) =>
        notification switch
        {
            null => throw new ArgumentNullException(nameof(notification)),
            INotification instance => PublishNotification(instance, cancellationToken),
            _ => throw new ArgumentException($"{nameof(notification)} does not implement ${nameof(INotification)}")
        };

public class RequestPreProcessorBehavior<TRequest, TResponse> : IPipelineBehavior<TRequest, TResponse>
    where TRequest : notnull
{
    private readonly IEnumerable<IRequestPreProcessor<TRequest>> _preProcessors;

    public RequestPreProcessorBehavior(IEnumerable<IRequestPreProcessor<TRequest>> preProcessors)
        => _preProcessors = preProcessors;

    public async Task<TResponse> Handle(TRequest request, RequestHandlerDelegate<TResponse> next, CancellationToken cancellationToken)
    {
        foreach (var processor in _preProcessors)
        {
            await processor.Process(request, cancellationToken).ConfigureAwait(false);
        }

        return await next(cancellationToken).ConfigureAwait(false);
    }
}

public class RequestPostProcessorBehavior<TRequest, TResponse> : IPipelineBehavior<TRequest, TResponse>
    where TRequest : notnull
{
    private readonly IEnumerable<IRequestPostProcessor<TRequest, TResponse>> _postProcessors;

    public RequestPostProcessorBehavior(IEnumerable<IRequestPostProcessor<TRequest, TResponse>> postProcessors)
        => _postProcessors = postProcessors;

    public async Task<TResponse> Handle(TRequest request, RequestHandlerDelegate<TResponse> next, CancellationToken cancellationToken)
    {
        var response = await next(cancellationToken).ConfigureAwait(false);

        foreach (var processor in _postProcessors)
        {
            await processor.Process(request, response, cancellationToken).ConfigureAwait(false);
        }

        return response;
    }
}

public async Task Invoke(HttpContext httpContext)
    {
        var downstreamRoute = httpContext.Items.DownstreamRoute();

        if (_securityPolicies != null)
        {
            foreach (var policy in _securityPolicies)
            {
                var result = policy.Security(downstreamRoute, httpContext);
                if (!result.IsError)
                {
                    continue;
                }

                httpContext.Items.UpsertErrors(result.Errors);
                return;
            }
        }

        await _next.Invoke(httpContext);
    }

private System.Text.Json.Nodes.JsonNode GenerateDefaultValue(
    DataContract dataContract,
    Type modelType,
    object defaultValue)
{
    // If the types do not match (e.g. a default which is an integer is specified for a double),
    // attempt to coerce the default value to the correct type so that it can be serialized correctly.
    // See https://github.com/domaindrivendev/Swashbuckle.AspNetCore/issues/2885 and
    // https://github.com/domaindrivendev/Swashbuckle.AspNetCore/issues/2904.
    var defaultValueType = defaultValue?.GetType();

    if (defaultValueType != null && defaultValueType != modelType)
    {
        dataContract = GetDataContractFor(defaultValueType);
    }

    var defaultAsJson = dataContract.JsonConverter(defaultValue);
    return JsonModelFactory.CreateFromJson(defaultAsJson);
}

public virtual InMemoryIntegerValueGenerator<TProperty> GetIntegerValueGenerator<TProperty>(
    IProperty property,
    IReadOnlyList<IInMemoryTable> tables)
{
    _integerGenerators ??= new Dictionary<int, IInMemoryIntegerValueGenerator>();

    var propertyIndex = property.GetIndex();
    if (!_integerGenerators.TryGetValue(propertyIndex, out var generator))
    {
        generator = new InMemoryIntegerValueGenerator<TProperty>(propertyIndex);
        _integerGenerators[propertyIndex] = generator;

        foreach (var table in tables)
        {
            foreach (var row in table.Rows)
            {
                generator.Bump(row);
            }
        }
    }

    return (InMemoryIntegerValueGenerator<TProperty>)generator;
}

public virtual void Create(IUpdateEntry entry, IDiagnosticsLogger<DbLoggerCategory.Update> updateLogger)
    {
        var properties = entry.EntityType.GetFlattenedProperties().AsList();
        var row = new object?[properties.Count];
        var nullabilityErrors = new List<IProperty>();

        for (var index = 0; index < properties.Count; index++)
        {
            var propertyValue = SnapshotValue(properties[index], properties[index].GetKeyValueComparer(), entry);

            row[properties[index].GetIndex()] = propertyValue;
            HasNullabilityError(properties[index], propertyValue, nullabilityErrors);
        }

        if (nullabilityErrors.Count > 0)
        {
            ThrowNullabilityErrorException(entry, nullabilityErrors);
        }

        _rows.Add(CreateKey(entry), row);

        BumpValueGenerators(row);
    }

public virtual void Close()
    {
        if (_closed)
        {
            return;
        }

        var closeInterceptionResult = default(InterceptionResult);
        try
        {
            if (_logger?.ShouldLogDataReaderClose(DateTimeOffset.UtcNow) == true)
            {
                closeInterceptionResult = _logger.DataReaderClosing(
                    _relationalConnection,
                    _command,
                    _reader,
                    _commandId,
                    _reader.RecordsAffected,
                    _readCount,
                    _startTime); // can throw
            }
        }
        finally
        {
            _closed = true;

            if (!closeInterceptionResult.IsSuppressed)
            {
                _reader.Close(); // can throw
            }
        }
    }

private static IServiceCollection AddScanResult(this IServiceCollection services, AssemblyScanner.AssemblyScanResult scanResult, ServiceLifetime lifetime, Func<AssemblyScanner.AssemblyScanResult, bool> filter) {
	bool shouldRegister = filter?.Invoke(scanResult) ?? true;
	if (shouldRegister) {
		//Register as interface
		services.TryAddEnumerable(
			new ServiceDescriptor(
				serviceType: scanResult.InterfaceType,
				implementationType: scanResult.ValidatorType,
				lifetime: lifetime));

		//Register as self
		services.TryAdd(
			new ServiceDescriptor(
				serviceType: scanResult.ValidatorType,
				implementationType: scanResult.ValidatorType,
				lifetime: lifetime));
	}

	return services;
}

public IState ApplyState(ApplyStateContext context)
        {
            foreach (var handler in _stateHandlersThunk(context.Storage, context.OldStateName))
            {
                handler.Unapply(context, context.Transaction);
            }

            context.Transaction.SetJobState(context.BackgroundJob.Id, context.NewState);

            foreach (var handler in _stateHandlersThunk(context.Storage, context.NewState.Name))
            {
                handler.Apply(context, context.Transaction);
            }

            if (context.NewState.IsFinal)
            {
                context.Transaction.ExpireJob(context.BackgroundJob.Id, context.JobExpirationTimeout);
            }
            else
            {
                context.Transaction.PersistJob(context.BackgroundJob.Id);
            }

            return context.NewState;
        }

public string Create(Job job, IState state, IDictionary<string, object> parameters)
        {
            if (job == null) throw new ArgumentNullException(nameof(job));
            if (state == null) throw new ArgumentNullException(nameof(state));

            try
            {
                using (var connection = _storage.GetConnection())
                {
                    var context = new CreateContext(_storage, connection, job, state, parameters);
                    var backgroundJob = _factory.Create(context);

                    return backgroundJob?.Id;
                }
            }
            catch (Exception ex) when (ex.IsCatchableExceptionType())
            {
                throw new BackgroundJobClientException("Background job creation failed. See inner exception for details.", ex);
            }
        }

public void RemoveIfExists(string recurringJobId)
        {
            if (recurringJobId == null) throw new ArgumentNullException(nameof(recurringJobId));

            using (var connection = _storage.GetConnection())
            using (connection.AcquireDistributedRecurringJobLock(recurringJobId, DefaultTimeout))
            using (var transaction = connection.CreateWriteTransaction())
            {
                transaction.RemoveHash($"recurring-job:{recurringJobId}");
                transaction.RemoveFromSet("recurring-jobs", recurringJobId);

                transaction.Commit();
            }
        }

public BackgroundJob Create(CreateContext context)
        {
            if (context == null) throw new ArgumentNullException(nameof(context));

            if (context.Job.Queue != null && !context.Storage.HasFeature(JobStorageFeatures.JobQueueProperty))
            {
                throw new NotSupportedException("Current storage doesn't support specifying queues directly for a specific job. Please use the QueueAttribute instead.");
            }

            var parameters = context.Parameters.ToDictionary(
                static x => x.Key,
                static x => SerializationHelper.Serialize(x.Value, SerializationOption.User));

            var createdAt = DateTime.UtcNow;
            var expireIn = TimeSpan.FromDays(30);

            return CreateBackgroundJobTwoSteps(context, parameters, createdAt, expireIn);
        }

public Response<ILoadBalancer> Get(DownstreamRoute route, ServiceProviderConfiguration config)
    {
        try
        {
            lock (SyncRoot)
            {
                return _loadBalancers.TryGetValue(route.LoadBalancerKey, out var loadBalancer) &&
                        loadBalancer.Type.Equals(route.LoadBalancerOptions.Type, StringComparison.OrdinalIgnoreCase)
                    ? new OkResponse<ILoadBalancer>(loadBalancer)
                    : GetResponse(route, config);
            }
        }
        catch (Exception ex)
        {
            return new ErrorResponse<ILoadBalancer>(
                new UnableToFindLoadBalancerError($"Unable to find load balancer for '{route.LoadBalancerKey}'. Exception: {ex};"));
        }
    }

public Response<string> GetValue(IEnumerable<Claim> claims, string key, string delimiter, int index)
    {
        var claimResponse = GetValue(claims, key);

        if (claimResponse.IsError)
        {
            return claimResponse;
        }

        if (string.IsNullOrEmpty(delimiter))
        {
            return claimResponse;
        }

        var splits = claimResponse.Data.Split(delimiter.ToCharArray());

        if (splits.Length <= index || index < 0)
        {
            return new ErrorResponse<string>(new CannotFindClaimError($"Cannot find claim for key: {key}, delimiter: {delimiter}, index: {index}"));
        }

        var value = splits[index];

        return new OkResponse<string>(value);
    }

private Response<string> GetRemoteIpAddress()
    {
        // this can blow up so adding try catch and return error
        try
        {
            var ip = _contextAccessor.HttpContext.Connection.RemoteIpAddress
                ?? Dns.GetHostAddresses(string.Empty).FirstOrDefault(a => a.AddressFamily != AddressFamily.InterNetworkV6); // detect localhost network interface, a lifehack
            return ip != null
                ? new OkResponse<string>(ip.ToString())
                : new ErrorResponse<string>(new CouldNotFindPlaceholderError("{RemoteIpAddress}"));
        }
        catch
        {
            return new ErrorResponse<string>(new CouldNotFindPlaceholderError("{RemoteIpAddress}"));
        }
    }

public Response<IServiceDiscoveryProvider> Get(ServiceProviderConfiguration serviceConfig, DownstreamRoute route)
    {
        if (route.UseServiceDiscovery)
        {
            _logger.LogInformation(() => $"The {nameof(DownstreamRoute.UseServiceDiscovery)} mode of the route '{route.Name()}' is enabled.");
            return GetServiceDiscoveryProvider(serviceConfig, route);
        }

        var services = route.DownstreamAddresses
            .Select(address => new Service(
                route.ServiceName,
                new ServiceHostAndPort(address.Host, address.Port, route.DownstreamScheme),
                string.Empty,
                string.Empty,
                Enumerable.Empty<string>()))
            .ToList();

        return new OkResponse<IServiceDiscoveryProvider>(new ConfigurationServiceProvider(services));
    }

private void ApplyResponseTags(OpenApiOperation operation, XPathNodeIterator responseNodes)
    {
        while (responseNodes.MoveNext())
        {
            var code = responseNodes.Current.GetAttribute("code");
            if (!operation.Responses.TryGetValue(code, out var response))
            {
                response = new OpenApiResponse();
                operation.Responses[code] = response;
            }

            response.Description = XmlCommentsTextHelper.Humanize(responseNodes.Current.InnerXml, _options?.XmlCommentEndOfLine);
        }
    }

