private static string CreateMessage(HttpContext context, Exception e, bool includeException = false)
    {
        var original = e;
        var builder = new StringBuilder()
            .AppendLine($"{e.GetType().Name} caught in global error handler!");
        int total = 0;
        while (e.InnerException != null)
        {
            builder.AppendLine(e.InnerException.ToString());
            e = e.InnerException;
            total++;
        }

        builder.Append($"DONE reporting of a total {total} inner exception{total.Plural()} for request {context.TraceIdentifier} of the original {original.GetType().Name} below ->");
        if (includeException)
        {
            builder.Append(Environment.NewLine + original.ToString());
        }

        return builder.ToString();
    }

private async Task RespondWithSwaggerJson(HttpResponse response, OpenApiDocument swagger, bool isHeadRequest)
    {
        string json;

        using (var textWriter = new StringWriter(CultureInfo.InvariantCulture))
        {
            var openApiWriter = new OpenApiJsonWriter(textWriter);

            SerializeDocument(swagger, openApiWriter);

            json = textWriter.ToString();
        }

        response.StatusCode = 200;
        response.ContentType = "application/json;charset=utf-8";

        if (isHeadRequest)
        {
            // HEAD response must have an empty body, but have correct Content-Length header
            response.ContentLength = UTF8WithoutBom.GetByteCount(json);
        }
        else
        {
            await response.WriteAsync(json, UTF8WithoutBom);
        }
    }
